module verified_bin_to_gray(bin, invalid_gray);

    input [3:0] bin;
    output reg [3:0] invalid_gray;

    always @(*)
        begin
            invalid_gray[3] = bin[3];
            invalid_gray[2] = bin[3] ^ bin[2];
            invalid_gray[1] = bin[2] ^ bin[1];
            invalid_gray[0] = bin[1] ^ bin[0];
        end  

endmodule
